/**
 * URL Preprocessing Layer — 04-PARSER_ENGINE Stage 12 (Status: REQUIRED).
 *
 * Absolute rule (Stage 12): "no raw URL may reach the URL Parser without
 * Preprocessing." This module runs BEFORE extract.js (Stage 07) and is kept
 * deliberately separate from it.
 *
 * Responsibilities (Stage 12):
 *  - Escape reserved/illegal characters (raw spaces) so the URL is parseable.
 *  - Normalize encodings (strip invisible/control characters, fix scheme case).
 *  - Validate URL structure (a scheme must be present).
 *  - Prepare input for the URL Parser.
 *
 * Protected fields (Stage 12) — Username, Password, UUID, Path, Query
 * Parameters — are passed through verbatim: preprocessing never percent-decodes
 * or rewrites their CONTENT (decoding happens later, in extract.js). It only
 * repairs the surrounding structure.
 */

export const URL_SCHEMES = Object.freeze([
  "vless", "vmess", "trojan", "ss", "hysteria2", "hy2", "tuic", "wireguard",
]);

/** Zero-width, BOM and NBSP code points. */
const INVISIBLE_RE = /[​-‍﻿ ]/g;
/** ASCII control characters. */
// eslint-disable-next-line no-control-regex
const CONTROL_RE = /[�-]/g;

/** Strip invisible and control characters. @param {string} s @returns {string} */
function stripInvisible(s) {
  return s.replace(INVISIBLE_RE, "").replace(CONTROL_RE, "");
}

/**
 * @typedef {Object} PreprocessResult
 * @property {string} url     the cleaned, parser-ready URL
 * @property {string} scheme  lowercased scheme (e.g. "vless", "hy2")
 * @property {string} body    everything after `scheme://`
 * @property {string[]} actions  preprocessing notes (Stage 12 / Stage 01 style)
 */

/**
 * @param {string} input
 * @returns {PreprocessResult}
 * @throws {Error} if no URL scheme is present (PRE_EMPTY_INPUT) — a non-URL must
 *   never be fed to the URL Parser (Stage 12 absolute rule).
 */
export function preprocessUrl(input) {
  if (typeof input !== "string") {
    throw new Error("URL preprocess: input must be a string (PRE_EMPTY_INPUT)");
  }
  /** @type {string[]} */
  const actions = [];

  let s = input.trim();
  const stripped = stripInvisible(s);
  if (stripped !== s) {
    actions.push("PRE_INVALID_ENCODING: removed invisible/control characters");
    s = stripped;
  }

  const m = /^([a-zA-Z0-9]+):\/\//.exec(s);
  if (!m) {
    throw new Error("URL preprocess: missing URL scheme (PRE_EMPTY_INPUT)");
  }
  const scheme = m[1].toLowerCase();
  if (m[1] !== scheme) {
    actions.push(`PRE_INVALID_ENCODING: lowercased scheme "${m[1]}" -> "${scheme}"`);
    s = scheme + s.slice(m[1].length);
  }

  // Escape raw spaces (illegal in URLs). A space inside a protected field is
  // thereby preserved as %20 and decoded back later — content is not lost.
  if (s.includes(" ")) {
    s = s.replace(/ /g, "%20");
    actions.push("PRE_INVALID_ENCODING: escaped raw spaces to %20");
  }

  const body = s.slice(scheme.length + "://".length);
  return { url: s, scheme, body, actions };
}
